const express = require('express');
const { Pool } = require('pg');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

const pool = new Pool({
  user: 'your_superuser',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

app.post('/create', async (req, res) => {
  const { table, data } = req.body;
  try {
    const query = `INSERT INTO ${table}(${Object.keys(data).join(',')}) VALUES(${Object.values(data).map((_, i) => `$${i + 1}`).join(',')}) RETURNING *`;
    const result = await pool.query(query, Object.values(data));
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.get('/read/:table', async (req, res) => {
  const { table } = req.params;
  try {
    const result = await pool.query(`SELECT * FROM ${table}`);
    res.status(200).json(result.rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.put('/update/:table/:id', async (req, res) => {
  const { table, id } = req.params;
  const data = req.body;
  try {
    const query = `UPDATE ${table} SET ${Object.keys(data).map((key, i) => `${key}=$${i + 1}`).join(',')} WHERE id=$${Object.keys(data).length + 1} RETURNING *`;
    const result = await pool.query(query, [...Object.values(data), id]);
    res.status(200).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.delete('/delete/:table/:id', async (req, res) => {
  const { table, id } = req.params;
  try {
    const result = await pool.query(`DELETE FROM ${table} WHERE id=$1 RETURNING *`, [id]);
    res.status(200).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});